var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"크읏, 대체 뭐냐!","JPN":"くうっ、いったい何なんだ！","ENG":"Ugh, what the hell?","TWN":"呃，怎麼回事！"},"stage":{"bg":"BLACK","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"분명 제대로 조준했을 텐데, 어째서 저 꼬맹인 한 대도 맞질 않는 거지?","JPN":"しっかり照準を合わせてるのに、なぜあのチビにはまったく当たらないんだ！？","ENG":"Why can't I hit her, no matter how carefully I aim?","TWN":"我明明瞄準好了，為什麼就是打不到那個小鬼？"},"stage":{"bg":"BLACK","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"흐흥~ 그 정도로는 내 옷깃도 건드릴 수 없을 텐데.","JPN":"ふふーんだ。その程度じゃ私の襟にも届かないよ？","ENG":"Heh, you can't even leave a scratch on me doing that.","TWN":"哼～就憑這種程度是打不到我的喔。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어때? 이제 내 대단함을 알겠어?","JPN":"どう？　私のスゴさ、わかったでしょ？","ENG":"Say, do you know how great I am now?","TWN":"怎麼樣？知道我有多厲害了吧？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......그래, 그랬군.","JPN":"……そうか、そうだったのか。","ENG":"Yes, I see.","TWN":"……是嗎，原來如此。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"너 이 자식! 날 속였구나! 이건 홀로그램일 뿐이잖아!","JPN":"てめえ、俺を騙してやがったな！　これはただの\\nホログラムじゃないか！","ENG":"You little demon! You fooled me! This is just a hologram!","TWN":"你這傢伙！你騙我！你只是全息影像而已！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하하, 이제 알아챈 거야?","JPN":"アハハ、今頃気付いたの？","ENG":"Teehee! Now you know.","TWN":"哈哈，你才發現嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그치만 이미 속을대로 속았지롱~? 내 친구들은 이미 다 풀려났는걸?","JPN":"でも、もう遅いんだよーんだ。私の仲間は全員\\n解放されたんだから。","ENG":"But it's too late now. All my friends have gotten away from you.","TWN":"可惜已經太晚了～我的朋友們已經被救出來了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"잘난 체 하는 것도 거기까지다!","JPN":"調子に乗るのもそこまでだ！","ENG":"I'm tired of your arrogance!","TWN":"別高興地太早！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"함선에 손상이 갈 것 같아서 일부러 출력을 조절하고 있었다만......","JPN":"艦船を傷つけそうで、あえて力を加減していたが……","ENG":"I didn't go all out because I didn't want to damage my ship,","TWN":"我是因為怕影響到艦船才故意調整了功率……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이렇게 된 이상, 여길 모조리 불바다로 만들어주마!","JPN":"こうなった以上、ここを火の海にしてやる！","ENG":"but I don't care anymore. I'm going to set it on fire along with everything in it!","TWN":"不過事已至此，我就把這裡燒成火海！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"네 기계친구들이 양초처럼 녹은 뒤에도 그렇게 웃을 수 있는지 두고 보지!","JPN":"お前の機械仲間がロウソクのように溶けても\\n笑っていられるか、見てやろうじゃないか！","ENG":"Let's see if you still can laugh after all your friends turn into pools of molten metal!","TWN":"等你的機械朋友都像蠟燭一樣融化掉之後，我看你還能不能笑得出來！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이런! 위험하네! 내 뒤로 피하게나!","JPN":"ハッ！　危険だ！　吾輩の後ろに隠れたまえ！","ENG":"Oh, no! This is dangerous! Get behind me!","TWN":"啊！危險！快躲到我身後！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"괘, 괜찮아, 할아버지?","JPN":"だ、大丈夫？　おじいちゃん？","ENG":"G-Grandpa, are you okay?","TWN":"沒、沒事嗎，爺爺？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L37_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 저 해적친구의 개조 때문인지 상당한 출력이야. 관절부가 꽤 따끔하군!","JPN":"うむ！　あの海賊の改造で相当な力が加わったんだな。\\n関節部がかなりヒリヒリしている！","ENG":"Mm! That pirate woman knows what she's doing. My joints tingle now.","TWN":"嗯！那個海盜好大的功率，關節有些刺痛！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"미안...... 내가 괜히 쓸데없는 짓을 해서......","JPN":"ごめんね……私が余計なことをしたせいで……","ENG":"Sorry... I shouldn't have provoked her...","TWN":"對不起……是我太大意了……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"걱정 말게나! 시그마를 위해서라면 이 정도는 영광의 상처라네!","JPN":"案ずるな！　これくらいのケガ、シグマのためなら\\n喜んで負ってやる！","ENG":"Don't worry. I can do this again anytime for you, Sigma.","TWN":"不用擔心！為了保護西格瑪而受傷是光榮的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그리고 우리 결전병기 친구끼리는 서로 돕기로 하지 않았나!","JPN":"それに我が決戦兵器たる者同士、お互い\\n助け合うと約束したじゃないか！","ENG":"Besides, we're Ultimate Doomsday Weapons. We promised to help each other.","TWN":"我們不是說過我們決戰兵器朋友之間要互相幫助嗎！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자! 고작 이런 걸로 주눅들지 말고 함께 싸우세!","JPN":"さあ！　この程度のことで怯むでないぞ！\\n一緒に戦おう！","ENG":"Now, stop beating yourself up and let's fight together.","TWN":"來！別因為這點小事氣餒，一起戰鬥吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"응...... 고마워 할아버지, 이 상처는 내가 꼭 고쳐줄게!","JPN":"うん……ありがとう、おじいちゃん。このケガは私が\\nきっと治してあげるからね！","ENG":"Okie. Thank you, Grandpa. I'll fix you. I promise.","TWN":"嗯……謝謝你，爺爺，我一定會幫你治好這個傷口。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"흐음, 뭔가 했더니 그 직육면체가 네 본체의 모습이었나?","JPN":"ほほう、何かと思ったらその直方体がお前の\\n本体の姿だったのか。","ENG":"Hm, that's what you really are, a cuboid robot.","TWN":"嗯，原來那個直六面體就是你的本體嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하하! 그런 주제에 사람 모습의 홀로그램을 쓰고 있다니 기가 막히는군.","JPN":"ハハハ！　そのくせに人間のようなホログラムを\\nかぶってるなんて、あきれたもんだ。","ENG":"Hah hah! And you used a hologram to pretend to be a girl?","TWN":"哈哈！你長這副摸樣還用全息影像模仿人類，真是可笑。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그래, 가끔 있었지. 주제도 모르고 사람이 되고 싶어하는 불량품들.","JPN":"まあ、たまにいたがな。身の程を知らず人間になりたがる\\n不良品どもは。","ENG":"Yes, I've seen your type. Defects that don't know their place and want to be human.","TWN":"對了，確實有一些瑕疵品不知分寸地妄想成為人類。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하지만 그런 불량품들의 결말은 언제나 한결 같지.","JPN":"だが、そんな不良品どもの結末はいつも決まってるんだ。","ENG":"And all those defects meet the same end.","TWN":"那些瑕疵品都只有一個結果。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그런 명령도 안 듣는 불쾌한 것들은 폐기! 즉결 폐기처분이다!","JPN":"命令もきかないそんな不快な奴らは廃棄！\\n即決処分で廃棄あるのみだ！","ENG":"Such unpleasant and disobedient machines are to be disposed of. At once!","TWN":"那些令人討厭的東西會報廢！立即報廢！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"맞아. 난 기계야.","JPN":"そのとおりだよ。私は機械。","ENG":"Yes, I'm a machine.","TWN":"沒錯，我是機器。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L50_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"아빠 같은 사람과는 달라.","JPN":"パパのような人間たちとは違う。","ENG":"I'm not a human like Daddy.","TWN":"我和爸爸不一樣。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"내가 아무리 아이를 흉내 내도......","JPN":"私がどんなに人間の子どもの真似をしても……","ENG":"It doesn't change...","TWN":"我無論再怎麼模仿孩子……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"그 사실엔 변함이 없어.","JPN":"その事実はかわらない。","ENG":"no matter how realistic I look as a girl.","TWN":"這個事實也不會改變。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"호오, 주제 파악은 빨라서 마음에 드는걸.","JPN":"ほほう、聞き分けの良い子だな。気に入った。","ENG":"Ah, at least you know place.","TWN":"哦，你還挺有自知之明的嘛。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"지금이라도 순순히 투항하면 네 다른 기계친구들은 녹이지 않겠다.","JPN":"今からでもおとなしく投降すれば、お前の機械仲間を\\n溶かすのはやめてやる。","ENG":"If you surrender now, I won't hurt your machine friends.","TWN":"如果趁現在乖乖投降，我就可以放過你的其他機械朋友。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"네가 샘플이 된다면 훌륭한 <color=#ffd34c>작품</color>이 나올 것 같으니까,","JPN":"お前がサンプルになれば、立派な<color=#ffd34c>コレクション</color>に\\nなりそうだからな。","ENG":"I think I can make a great <color=#ffd34c>masterpiece</color> with you.","TWN":"因為如果有了你這個樣本，我就能製作出很出色的<color=#ffd34c>作品</color>了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"나도 웬만해선 작품의 소재를 망가뜨리고 싶진 않거든.","JPN":"俺もコレクションの素材を壊すことはできるだけ\\n避けたいんだ。","ENG":"I don't want to damage my materials if I can help it.","TWN":"我不想損壞我的作品素材。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"하지만 난 내 꿈을 포기하지 않아.","JPN":"でも、私は自分の夢をあきらめないよ？","ENG":"But I'm not going to give up on my dreams.","TWN":"但我不會放棄我的夢想。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"나무로 된 인형도 요정의 힘으로, 나무꾼과 함께 가족이 될 수 있었으니까.","JPN":"木彫りのお人形も、妖精の力で木こりの家族になれたからね。","ENG":"The wooden doll became the woodcutter's family with help from the fairy.","TWN":"人偶也在妖精之力的幫助下，和樵夫成為了一家人。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......뭣이? 요정?","JPN":"……何だって？　妖精？","ENG":"What? Fairy?","TWN":"……什麼？妖精？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하하! 어린애도 안 믿는 그런 모순투성이 동화를 기계가 믿다니, 바보 같군!","JPN":"ハハハ！　あんな子どもでも信じない矛盾だらけの\\nおとぎ話を、まさか機械が信じるなんてな！　バカだな！","ENG":"Hah hah! Are you talking about some stupid fairy tale that even real children can hardly believe? So foolish!","TWN":"哈哈！機器人竟然會相信連三歲小孩都不會信的童話，太愚蠢了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"동화가 사실이냐, 거짓이냐는 중요하지 않아.","JPN":"おとぎ話の内容が本当か嘘なのかは、別にいいの。","ENG":"It doesn't matter if the story is true or not.","TWN":"童話是真是假並不重要。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"내가 그 이야기를 동경하고 있으니까.","JPN":"私がその物語に憧れていることが重要なんだから。","ENG":"Because I believe in it.","TWN":"重要的是我很憧憬那個故事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"행복한 이야기는 믿는 것만으로 행복해지기 때문에 가치가 있는 거야.","JPN":"幸せなストーリーは信じるだけで幸せになる。\\nだから、価値があるのよ。","ENG":"Happy stories make you happy when you believe in them.","TWN":"幸福故事的價值在於，會讓相信那個故事的人獲得幸福。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"날 만들어준 그 사람과 만나면서......","JPN":"私をつくってくれたあの人と出会ってから……","ENG":"When I met my maker,","TWN":"我和創造我的那個人相遇後……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"그 사람과 함께 가족이 되면 정말 행복할 거라고 생각했어.","JPN":"あの人と家族になれば、本当に幸せだろうなと思ったの。","ENG":"I wanted to become his family and live happily together.","TWN":"我一直希望和他成為一家人，那樣我一定會很幸福。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"그리고, 그 바람은 틀림없이 날 움직이게 해주는 원동력이야.","JPN":"そしてその願いは、間違いなく私を動かす原動力に\\nなっている。","ENG":"And that's what fuels me.","TWN":"並且，這個希望就是我的動力。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NAME_MECH","text":{"KOREA":"그 바람이야말로 날 살아있게 만들어주는 요정의 힘.","JPN":"その願いこそが私を生かしてくれる妖精の力。","ENG":"That's what makes me feel alive, the power of the fairy.","TWN":"這個希望就是給我賦予生命力的妖精之力。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NAME_MECH","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"내가 가진 삶의 가치야.","JPN":"私の人生の価値なの。","ENG":"It's what makes my life valuable.","TWN":"是我的人生所具有的價值。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_05"},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"내가 가진 가치는 당신 같은 악당의 욕심 따위보다 약하지 않아!","JPN":"その価値は、あなたのような悪党の強欲なんかに\\n負けないからね！","ENG":"And my life is much more valuable than your greed!","TWN":"我的價值比你這壞蛋的貪欲要更強大！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"악당을 혼내주고,","JPN":"悪党を懲らしめ、","ENG":"I'm going to punish you,","TWN":"我要教訓壞蛋，"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"친구들 모두를 구해서,","JPN":"仲間みんなを助けて、","ENG":"save all my friends,","TWN":"救出所有朋友，"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"당당히 아빠에게 돌아갈 거야!","JPN":"堂々とパパの元へ帰るから！","ENG":"and go back to Daddy as his proud girl!","TWN":"堂堂正正地回到爸爸身邊！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};